<?php require_once __DIR__.'/../includes/bootstrap.php';header('Content-Type: application/json');$token=$_SERVER['HTTP_X_API_TOKEN']??'';$s=$pdo->prepare("SELECT id FROM users WHERE api_token=?");$s->execute([$token]);$u=$s->fetch();if(!$u){http_response_code(401);echo json_encode(['error'=>'Unauthorized']);exit;}$uid=(int)$u['id'];$method=$_SERVER['REQUEST_METHOD'];$id=(int)($_GET['id']??0);$data=json_decode(file_get_contents('php://input'),true)?:[];if($method==='GET'){$s=$id?$pdo->prepare("SELECT * FROM tasks WHERE id=? AND (user_id=? OR assigned_to=?)"):$pdo->prepare("SELECT * FROM tasks WHERE user_id=? OR assigned_to=? ORDER BY id DESC");$s->execute($id?[$id,$uid,$uid]:[$uid,$uid]);echo json_encode(['data'=>$id?$s->fetch():$s->fetchAll()]);exit;}if($method==='POST'){$title=trim($data['title']??'');if(strlen($title)<3){http_response_code(422);echo json_encode(['error'=>'Title required']);exit;}$pdo->prepare("INSERT INTO tasks(user_id,title,status,priority,category,progress) VALUES(?,?,?,?,?,?)")->execute([$uid,$title,$data['status']??'todo',$data['priority']??'medium',$data['category']??'General',(int)($data['progress']??0)]);http_response_code(201);echo json_encode(['id'=>(int)$pdo->lastInsertId()]);exit;}if($method==='PUT'&&$id){$sets=[];$vals=[];foreach(['title','description','status','priority','due_date','category','tags','progress'] as $f)if(array_key_exists($f,$data)){$sets[]="$f=?";$vals[]=$data[$f];}if(!$sets){http_response_code(422);echo json_encode(['error'=>'No fields']);exit;}$vals[]=$id;$vals[]=$uid;$pdo->prepare("UPDATE tasks SET ".implode(',',$sets)." WHERE id=? AND user_id=?")->execute($vals);echo json_encode(['message'=>'Updated']);exit;}if($method==='DELETE'&&$id){$pdo->prepare("DELETE FROM tasks WHERE id=? AND user_id=?")->execute([$id,$uid]);echo json_encode(['message'=>'Deleted']);exit;}http_response_code(405);echo json_encode(['error'=>'Method not allowed']);